import{_ as t,o as l,c as n,j as e,a}from"./chunks/framework.Bp7r_-XI.js";const _=JSON.parse('{"title":"娘化剑术","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/杂项/娘化剑术.md","filePath":"4.资源分区/6.技艺及称号/杂项/娘化剑术.md"}'),s={name:"4.资源分区/6.技艺及称号/杂项/娘化剑术.md"};function o(d,r,i,p,c,h){return l(),n("div",null,[...r[0]||(r[0]=[e("h1",{id:"娘化剑术",tabindex:"-1"},[a("娘化剑术 "),e("a",{class:"header-anchor",href:"#娘化剑术","aria-label":'Permalink to "娘化剑术"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调019")])])],-1),e("h1",{id:"娘化剑术-1",tabindex:"-1"},[a("娘化剑术 "),e("a",{class:"header-anchor",href:"#娘化剑术-1","aria-label":'Permalink to "娘化剑术"'},"​")],-1),e("p",null,[a("娘化剑术"),e("br"),a(" B+2500")],-1),e("p",null,"这是一种失传已久的秘法，相传古代的驱魔师都使用此法驱散魔物。在数百年后，它被有心者重新发现并加以改良，似乎变得更有用了（？）。",-1),e("p",null,"施展娘化剑术的前提是杀死一只B级及以下的，可以被视作【魔物】的生物，一般而言这应该是指一只西幻世界中常见的非人类邪恶阵营生物，且不能为轮回者。",-1),e("p",null,"在杀死那只生物后，使用者可以正常施展娘化剑术，在尸体的死亡点结成一个法阵，将死亡的生物纳入法阵之中重新塑造并复活，复活时间为半个月至一个月不等，这是一个B级时空来源的复活效果。在成功复活后，那只生物无论原有的是什么性别，都将转变为女性（或雌性），并视为具有萌化改造，因此缩小体积，同时，被复活的生物的外貌将额外提升施术者的风度附加*5点外貌。但这并不意味着被复活的生物会对施术者忠诚，它会保持死亡时的心态而复活。",-1),e("hr",null,null,-1),e("p",null,"Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.",-1)])])}const m=t(s,[["render",o]]);export{_ as __pageData,m as default};
